+   12:     }
+   13: 
+   14:     public int EstimateDiffTokens(IReadOnlyList<FileChange> files, int maxPatchLines)
+   15:     {
+   16:         ArgumentNullException.ThrowIfNull(files);
+   17: 
+   18:         var tokens = 0;
+   19:         foreach (var file in files)
+   20:         {
+   21:             tokens += EstimateFileTokens(file, maxPatchLines);
+   22:         }
+   23: 
+   24:         return tokens;
+   25:     }
+   26: 
+   27:     public IReadOnlyList<ReviewChunk> PlanChunks(
+   28:         IReadOnlyList<FileChange> files,
+   29:         int contentBudgetTokens,
+   30:         double headroom,
+   31:         int maxChunks,
+   32:         int maxPatchLines)
+   33:     {
+   34:         ArgumentNullException.ThrowIfNull(files);
+   35:         if (contentBudgetTokens < 0)
+   36:         {
+   37:             throw new ArgumentOutOfRangeException(nameof(contentBudgetTokens), contentBudgetTokens, "Content budget cannot be negative.");
+   38:         }
+   39: 
+   40:         if (headroom <= 0 || headroom > 1)
+   41:         {
+   42:             throw new ArgumentOutOfRangeException(nameof(headroom), headroom, "Chunk headroom must be greater than 0 and less than or equal to 1.");
+   43:         }
+   44: 
+   45:         if (maxChunks <= 0)
+   46:         {
+   47:             throw new ArgumentOutOfRangeException(nameof(maxChunks), maxChunks, "Maximum chunk count must be positive.");
+   48:         }
+   49: 
+   50:         if (files.Count == 0)
+   51:         {
+   52:             return [];
+   53:         }
+   54: 
+   55:         var targetTokens = Math.Max(1, (int)Math.Floor(contentBudgetTokens * headroom));
+   56:         var planned = new List<PlannedChunk>();
+   57:         var currentFiles = new List<FileChange>();
+   58:         var currentTokens = 0;
+   59: 
+   60:         foreach (var entry in files
+   61:             .Select(file => new FileTokenEstimate(file, EstimateFileTokens(file, maxPatchLines)))
+   62:             .OrderBy(file => DirectoryPrefix(file.File.Path), StringComparer.Ordinal)
+   63:             .ThenBy(file => file.File.Path, StringComparer.Ordinal))
+   64:         {
+   65:             if (currentFiles.Count > 0 && currentTokens + entry.Tokens > targetTokens)
+   66:             {
+   67:                 planned.Add(new PlannedChunk(currentFiles.ToArray(), currentTokens));
+   68:                 currentFiles.Clear();
+   69:                 currentTokens = 0;
+   70:             }
+   71: 
+   72:             currentFiles.Add(entry.File);
+   73:             currentTokens += entry.Tokens;
+   74:         }
+   75: 
+   76:         if (currentFiles.Count > 0)
+   77:         {
+   78:             planned.Add(new PlannedChunk(currentFiles.ToArray(), currentTokens));
+   79:         }
+   80: 
+   81:         var capped = planned.Take(maxChunks).ToArray();
+   82:         return capped
+   83:             .Select((chunk, index) => new ReviewChunk(index + 1, capped.Length, chunk.Files, chunk.EstimatedTokens))
+   84:             .ToArray();
+   85:     }
+   86: 
+   87:     private int EstimateFileTokens(FileChange file, int maxPatchLines) =>
+   88:         tokenEstimator.EstimateTokens(
+   89:             $"{file.Path} {file.Status} +{file.AdditionsCount} -{file.DeletionsCount}\n{TakePatchLines(file.Patch, maxPatchLines)}");
+   90: 
+   91:     private static string TakePatchLines(string patch, int maxPatchLines)
+   92:     {
+   93:         if (maxPatchLines <= 0 || string.IsNullOrEmpty(patch))
+   94:         {
+   95:             return string.Empty;
+   96:         }
+   97: 
+   98:         return string.Join('\n', patch
+   99:             .Replace("\r\n", "\n", StringComparison.Ordinal)
+  100:             .Replace('\r', '\n')
+  101:             .Split('\n')
+  102:             .Take(maxPatchLines));
+  103:     }
+  104: 
+  105:     private static string DirectoryPrefix(string path)
+  106:     {
+  107:         var lastSlash = path.LastIndexOf('/');
+  108:         return lastSlash <= 0 ? string.Empty : path[..lastSlash];
+  109:     }
+  110: 
+  111:     private sealed record FileTokenEstimate(FileChange File, int Tokens);
+  112: 
+  113:     private sealed record PlannedChunk(IReadOnlyList<FileChange> Files, int EstimatedTokens);
+  114: }
